/** UsptBsnsChargerDao.update */
update uspt_bsns_charger
set
	updater_id			= #{updaterId}
	, updated_dt		= #{updatedDt}
	, reprsnt_charger	= #{reprsntCharger}
	, charger_author_cd	= #{chargerAuthorCd}
where
	bsns_cd = #{bsnsCd}
	and insider_id = #{insiderId}

